/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:collection/collection.dart';
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:url_launcher/url_launcher.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/session_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/utils/date.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/empty_view.dart';
import 'package:baseball_detector_flutter/views/components/paging_helper.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_team_check.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/session_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/session_search_bar_with_filter.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

/// A page widget class to manage session lists.
/// This class is the home page after logged in.
/// By tapping a session item, its `SessionDetailsPage` will open.
class SessionsPage extends HookConsumerWidget {
  const SessionsPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamId = ref.watch(
      profileStorageProvider.select((p) => p.getTeamId()),
    )!;
    final isSingleTeam = useSingleTeamCheck();
    final shouldValidatePlayers = !isSingleTeam;
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final canAddSession = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.basic,
          RoleLevel.write,
          false,
        ) ??
        false;
    final wordState = useState('');

    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: AutoDisposePagingHelper<SessionListController, Session>(
            provider: sessionListControllerProvider,
            pageSize: SessionListController.pageSize,
            contentBuilder: (pagingData, endItemView) {
              final filterParams =
                  ref.watch(sessionFilterParametersNotifierProvider);
              final isFilterActive = filterParams.player != null ||
                  filterParams.startDate != null ||
                  filterParams.endDate != null ||
                  (filterParams.location != null &&
                      filterParams.location!.isNotEmpty);

              final word = wordState.value.trim();
              final items = word.isEmpty
                  ? pagingData.items
                  : pagingData.items
                      .where((session) => (session.title ?? '').contains(word))
                      .toList();

              return SingleChildScrollView(
                physics: const AlwaysScrollableScrollPhysics(),
                child: Column(
                  children: [
                    if (context.isLandscape) const Gap(16),
                    SessionSearchBarWithFilter(
                      word: wordState.value,
                      onChanged: (v) => wordState.value = v,
                    ),
                    const Gap(12),
                    if (items.isEmpty)
                      EmptyView(
                        icon: isFilterActive ? Icons.search_off : Icons.inbox,
                        message: isFilterActive
                            ? context.l10n.sessions_page__no_filtered_data
                            : context.l10n.sessions_page__have_no_data,
                      )
                    else ...[
                      _SessionMonthGroupList(
                        sessions: items,
                        onSessionTap: (session) {
                          if (session.teamId != null) {
                            Navigator.of(context).pushNamed(
                                HomeRouter.sessionDetailsPage,
                                arguments: {
                                  'teamId': session.teamId,
                                  'sessionId': session.id,
                                  'session': session,
                                });
                          }
                        },
                      ),
                      if (endItemView != null) endItemView,
                      const Gap(24),
                      const _IntroductionVideoLink(),
                      const Gap(24),
                    ],
                  ],
                ),
              );
            },
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        backgroundColor: canAddSession
            ? null
            : context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
        onPressed: canAddSession
            ? () async {
                if (shouldValidatePlayers) {
                  try {
                    final players = await ref.read(allPlayersProvider.future);
                    if (!context.mounted) return;
                    if (players.isEmpty) {
                      context.showErrorSnackBar(
                        context.l10n.sessions_page__player_required_warning,
                      );
                      return;
                    }
                  } catch (error) {
                    if (!context.mounted) return;
                    final message = error is Failure
                        ? error.translate(context.l10n)
                        : error.toString();
                    context.showErrorSnackBar(message);
                    return;
                  }
                }

                if (!context.mounted) return;
                Navigator.of(context).pushNamed(HomeRouter.addSessionPage);
              }
            : null,
        child: Icon(Icons.add_circle_outline),
      ),
    );
  }
}

class _SessionMonthGroupList extends StatelessWidget {
  const _SessionMonthGroupList({
    required this.sessions,
    required this.onSessionTap,
  });

  final List<Session> sessions;
  final void Function(Session session) onSessionTap;

  @override
  Widget build(BuildContext context) {
    // Group sessions by month
    final groupedSessions = sessions
        .sorted((a, b) => b.createdAt!.compareTo(a.createdAt!))
        .groupListsBy((element) => DateTime(
              element.createdAt!.toLocal().year,
              element.createdAt!.toLocal().month,
            ))
        .entries
        .toList();

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: groupedSessions
          .map((e) {
            final dateTime = e.key;
            final sessionList = e.value;
            return [
              Text(
                dateTimeToString(
                  template: context.l10n.month_format,
                  locale: Localizations.localeOf(context).languageCode,
                  timestamp: dateTime,
                ).toUpperCase(),
                style: TextStyle(
                  fontSize: FontSize.s14,
                  fontWeight: FontWeight.w500,
                  color: context.isDarkMode
                      ? ColorManager.darkSecondaryText
                      : ColorManager.secondaryText,
                  height: 1.7,
                ),
              ),
              const Gap(12),
              ...sessionList.map((session) {
                return Padding(
                  padding: const EdgeInsets.only(bottom: 12),
                  child: SessionCard(
                    session: session,
                    onSessionTap: () => onSessionTap(session),
                  ),
                );
              }),
            ];
          })
          .expand((x) => x)
          .toList(),
    );
  }
}

class _IntroductionVideoLink extends StatelessWidget {
  const _IntroductionVideoLink();

  static const _youtubeUrl = 'https://www.youtube.com/watch?v=MmLiqbqUaSg';

  Future<void> _launchUrl() async {
    final uri = Uri.parse(_youtubeUrl);
    if (!await launchUrl(uri, mode: LaunchMode.externalApplication)) {
      throw Exception('Could not launch $_youtubeUrl');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Container(
      decoration: BoxDecoration(
        borderRadius: BorderRadius.circular(12),
        border: Border.all(
          color: context.isDarkMode
              ? ColorManager.darkSecondaryText.withOpacity(0.3)
              : ColorManager.secondaryText.withOpacity(0.3),
        ),
      ),
      child: Material(
