    final openTermsOfUse = useTermsOfUse();
    final openPrivacyPolicy = usePrivacyPolicy();
    final showNoti = ref.watch(showNotiBadgeProvider);
    final isJa = ref.watch(localeControllerProvider).isJapanese;

    return Card(
      child: Column(
        children: [
          NavigationItem(
            icon: Icons.notifications_outlined,
            text: context.l10n.settings_page__notifications,
            showNoti: showNoti.value == true,
            onTap: () {
              ref.read(showNotiBadgeProvider.notifier).setShowNotiBadge(false);
              Navigator.of(context).pushNamed(
                HomeRouter.notificationListPage,
              );
            },
          ),
          NavigationItem(
            icon: Icons.play_circle_outline,
            text: context.l10n.sessions_page__introduction_video_title,
            onTap: () {
              final url = isJa
                  ? Constants.howToUseSmartScoutURLJa
                  : Constants.howToUseSmartScoutURLEn;
              openURLWithSystemBrowser(url: url);
            },
          ),
          NavigationItem(
            icon: Icons.description_outlined,
            text: context.l10n.settings_page__terms,
            onTap: openTermsOfUse,
          ),
          NavigationItem(
            icon: Icons.privacy_tip_outlined,
            text: context.l10n.settings_page__privacy,
            onTap: openPrivacyPolicy,
          ),
          NavigationItem(
            icon: Icons.code_outlined,
            text: context.l10n.settings_page__license,
            onTap: () {
              Navigator.of(context).pushNamed(HomeRouter.licensePage);
            },
          ),
          if (isDevOrTest)
            NavigationItem(
              icon: Icons.analytics_outlined,
              text: 'License Checker',
              onTap: () {
                Navigator.of(context).pushNamed(HomeRouter.licenseCheckerPage);
              },
            ),
          // TODO: Remove this environmental condition
          if (!isPrd)
            NavigationItem(
              icon: Icons.support_agent_outlined,
              text: context.l10n.settings_page__contact_us,
              onTap: () => launchContactForm(userInfo),
            ),
        ],
      ),
    );
  }
}

