VoidCallback useTutorialVideo() {
  final ref = useWidgetRef();
  final locale = ref.watch(localeControllerProvider);

  return useCallback(() {
    final url = locale.isJapanese
        ? Constants.howToUseSmartScoutURLJa
        : Constants.howToUseSmartScoutURLEn;
    openURLWithSystemBrowser(url: url);
  }, [locale]);
}
